mapper.select:
SELECT o.id, o.order_no AS orderNo, o.student_id AS studentId, s.name AS studentName, o.session_id AS sessionId, cs.session_name AS sessionName, o.rank_category AS rankCategory, o.accommodation_type AS accommodationType, o.room_match_status AS roomMatchStatus, o.total_amount AS amount, o.payment_status AS paymentStatus, o.order_status AS orderStatus, o.create_time AS createTime FROM registration_order o LEFT JOIN student s ON o.student_id = s.id LEFT JOIN camp_session cs ON o.session_id = cs.id WHERE o.is_deleted = 0
AND s.name LIKE CONCAT('%', #{studentName}, '%')
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND o.session_id = #{sessionId}
AND o.payment_status = #{paymentStatus}
AND o.room_match_status = #{roomMatchStatus}
AND DATE(o.create_time) >= #{startDate}
AND DATE(o.create_time) <= #{endDate}
ORDER BY o.create_time DESC
